import java.util.*;
import java.util.concurrent.*;

public class CollectionScenariosDemo {
    public static void main(String[] args) {
        Map<String, String> sessionCache = new ConcurrentHashMap<>();
        List<String> cart = new ArrayList<>();
        Set<String> wishlist = new HashSet<>();
        Queue<String> orders = new PriorityQueue<>();

        sessionCache.put("s1", "user-Ravi");
        cart.add("Laptop"); cart.add("Mouse");
        wishlist.add("Headphones");
        orders.offer("ORD-100");

        System.out.println(sessionCache.get("s1"));
        System.out.println("Cart: " + cart);
        System.out.println("Wishlist unique: " + wishlist);
        System.out.println("Next order: " + orders.poll());
    }
}
